<?php session_start(); require_once '../config/database.php'; if (!isset($_SESSION['user_id'])) { header("Location: ../index.php"); exit(); } if (!isset($_GET['file_id'])) { die("File not found"); } $file_id = intval($_GET['file_id']); $query = "SELECT file_name FROM faculty_uploads WHERE id = ?"; $stmt = $conn->prepare($query); $stmt->bind_param("i", $file_id); $stmt->execute(); $result = $stmt->get_result(); if ($result->num_rows === 0) { die("File not found in database"); } $file = $result->fetch_assoc(); $file_path = "../uploads/" . $file['file_name']; if (!file_exists($file_path)) { die("File not found on server"); } header('Content-Type: application/octet-stream'); header('Content-Disposition: attachment; filename="' . basename($file_path) . '"'); header('Content-Length: ' . filesize($file_path)); readfile($file_path); exit(); ?>